arguments.argument:
if global.gamePaused=false
{
  if extraHitFrameBuffer>0 {extraHitFrameBuffer-=1}
  
  if atkProg=0
  {
    y-=2
    if y<=64
    {
      image_blend=c_white
      bCanDealDamage=true
      direction=point_direction(x,y,oPlayer1.x,oPlayer1.y-32)
      atkTime=0; atkProg=1
    }
  }
  else if atkProg=1
  {
    speed=bulletSpeed
  }
}
else {speed=0}
